<?php $heading=$job['title'];$subheading=$job['department'].' · '.$job['location'];require __DIR__.'/../public/_hero.php';?><section class="section business-detail"><article><div class="business-meta"><b><?=e(ucwords(str_replace('_',' ',$job['employment_type'])))?></b><span><?=$job['vacancy']?> vacancy</span><span>Deadline <?=date('d M Y',strtotime($job['application_deadline']))?></span></div><h2>About this role</h2><p><?=nl2br(e($job['summary']))?></p><h2>Responsibilities</h2><p><?=nl2br(e($job['responsibilities']))?></p><h2>Requirements</h2><p><?=nl2br(e($job['requirements']))?></p><h2>Salary</h2><p><?=e($job['salary_range']?:'As per hospital policy')?></p></article><form class="form-card" method="post" enctype="multipart/form-data" action="<?=url('career/apply')?>"><h2>Apply now</h2><?=csrf_field()?><input type="hidden" name="job_id" value="<?=$job['id']?>"><?php foreach(['full_name'=>'Full name','email'=>'Email','phone'=>'Phone','address'=>'Address','education'=>'Education','experience_years'=>'Experience in years']as$n=>$label):?><label><?=$label?><input name="<?=$n?>" value="<?=e($old[$n]??'')?>" <?=$n==='address'?'':'required'?>></label><?php if(!empty($errors[$n])):?><small class="field-error"><?=e($errors[$n][0])?></small><?php endif;?><?php endforeach;?><label>Cover letter<textarea name="cover_letter" rows="5"><?=e($old['cover_letter']??'')?></textarea></label><label>Résumé (PDF, DOC or DOCX; maximum 5 MB)<input type="file" name="resume" accept=".pdf,.doc,.docx" required></label><?php if(!empty($errors['resume'])):?><small class="field-error"><?=e($errors['resume'][0])?></small><?php endif;?><button class="btn">Submit Application</button></form></section>
